import React, { useState, useEffect } from 'react';
import AuthService from '../services/AuthService';
import { useNavigate } from 'react-router-dom';

function Login() {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    // Check if already logged in
    if (AuthService.isLoggedIn()) {
      navigate('/jobs');
    }
  }, [navigate]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      const response = await AuthService.login(username, password);
      AuthService.saveToken(response.data.token);

      // Trigger custom event to notify App.js of login status change
      window.dispatchEvent(new Event('authChanged'));

      // Slight delay to ensure state updates
      setTimeout(() => {
        navigate('/jobs');
      }, 100);
    } catch (err) {
      setError('Tên đăng nhập hoặc mật khẩu không đúng');
      setLoading(false);
    }
  };

  const handleDemoLogin = async (role) => {
    setError('');
    setLoading(true);

    const demoCredentials = {
      candidate: { username: 'candidate', password: 'password' },
      employer: { username: 'employer', password: 'password' },
      admin: { username: 'admin', password: 'password' }
    };

    try {
      const creds = demoCredentials[role];
      const response = await AuthService.login(creds.username, creds.password);
      AuthService.saveToken(response.data.token);

      window.dispatchEvent(new Event('authChanged'));
      setTimeout(() => {
        navigate('/jobs');
      }, 100);
    } catch (err) {
      setError('Không thể đăng nhập với tài khoản demo');
      setLoading(false);
    }
  };

  return (
    <div className="container" style={{
      minHeight: '100vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      background: 'linear-gradient(135deg, var(--primary-color), var(--primary-hover))',
      animation: 'fadeIn 0.8s ease-out'
    }}>
      <div className="login-card" style={{
        backgroundColor: 'var(--card-bg)',
        padding: '3rem',
        borderRadius: 'var(--border-radius)',
        boxShadow: '0 20px 40px rgba(0,0,0,0.1)',
        width: '100%',
        maxWidth: '450px',
        animation: 'slideInScale 0.6s ease-out'
      }}>
        <div style={{ textAlign: 'center', marginBottom: '2rem' }}>
          <h1 style={{
            color: 'var(--primary-color)',
            marginBottom: '0.5rem',
            fontSize: '2.5rem',
            fontWeight: '700'
          }}>
            🚀 JobPortal
          </h1>
          <p style={{ color: 'var(--text-secondary)', fontSize: '1.1rem' }}>
            Đăng nhập để tiếp tục
          </p>
        </div>

        {error && (
          <div className="alert alert-danger" style={{
            animation: 'shake 0.5s ease-in-out',
            marginBottom: '1.5rem'
          }}>
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit} style={{ marginBottom: '2rem' }}>
          <div className="form-group" style={{ marginBottom: '1.5rem' }}>
            <label style={{
              display: 'block',
              marginBottom: '0.5rem',
              color: 'var(--text-primary)',
              fontWeight: '500'
            }}>
              👤 Tên đăng nhập
            </label>
            <input
              type="text"
              className="form-control"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              required
              style={{
                width: '100%',
                padding: '1rem',
                border: '2px solid var(--border-color)',
                borderRadius: 'var(--border-radius)',
                fontSize: '1rem',
                transition: 'all 0.3s ease',
                backgroundColor: 'var(--bg-color)'
              }}
              onFocus={(e) => e.target.style.borderColor = 'var(--primary-color)'}
              onBlur={(e) => e.target.style.borderColor = 'var(--border-color)'}
              placeholder="Nhập tên đăng nhập"
            />
          </div>

          <div className="form-group" style={{ marginBottom: '1.5rem' }}>
            <label style={{
              display: 'block',
              marginBottom: '0.5rem',
              color: 'var(--text-primary)',
              fontWeight: '500'
            }}>
              🔒 Mật khẩu
            </label>
            <div style={{ position: 'relative' }}>
              <input
                type={showPassword ? 'text' : 'password'}
                className="form-control"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
                style={{
                  width: '100%',
                  padding: '1rem',
                  paddingRight: '3rem',
                  border: '2px solid var(--border-color)',
                  borderRadius: 'var(--border-radius)',
                  fontSize: '1rem',
                  transition: 'all 0.3s ease',
                  backgroundColor: 'var(--bg-color)'
                }}
                onFocus={(e) => e.target.style.borderColor = 'var(--primary-color)'}
                onBlur={(e) => e.target.style.borderColor = 'var(--border-color)'}
                placeholder="Nhập mật khẩu"
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                style={{
                  position: 'absolute',
                  right: '1rem',
                  top: '50%',
                  transform: 'translateY(-50%)',
                  background: 'none',
                  border: 'none',
                  color: 'var(--text-secondary)',
                  cursor: 'pointer',
                  fontSize: '1.2rem'
                }}
              >
                {showPassword ? '🙈' : '👁️'}
              </button>
            </div>
          </div>

          <button
            type="submit"
            className="btn btn-primary"
            disabled={loading}
            style={{
              width: '100%',
              padding: '1rem',
              fontSize: '1.1rem',
              fontWeight: '600',
              border: 'none',
              borderRadius: 'var(--border-radius)',
              background: 'linear-gradient(135deg, var(--primary-color), var(--primary-hover))',
              color: 'white',
              cursor: loading ? 'not-allowed' : 'pointer',
              transition: 'all 0.3s ease',
              marginBottom: '1rem'
            }}
            onMouseEnter={(e) => {
              if (!loading) {
                e.target.style.transform = 'translateY(-2px)';
                e.target.style.boxShadow = '0 8px 20px rgba(0,0,0,0.2)';
              }
            }}
            onMouseLeave={(e) => {
              e.target.style.transform = 'translateY(0)';
              e.target.style.boxShadow = 'none';
            }}
          >
            {loading ? (
              <>
                <div className="loading" style={{ width: '20px', height: '20px', marginRight: '10px' }}></div>
                Đang đăng nhập...
              </>
            ) : (
              '🚀 Đăng Nhập'
            )}
          </button>
        </form>

        {/* Demo login buttons */}
        <div style={{ marginBottom: '2rem' }}>
          <p style={{
            textAlign: 'center',
            color: 'var(--text-secondary)',
            marginBottom: '1rem',
            fontSize: '0.9rem'
          }}>
            ────── Đăng nhập nhanh ──────
          </p>
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(120px, 1fr))',
            gap: '0.5rem'
          }}>
            <button
              onClick={() => handleDemoLogin('candidate')}
              disabled={loading}
              className="btn"
              style={{
                backgroundColor: 'var(--info-color)',
                color: 'white',
                border: 'none',
                padding: '0.75rem',
                borderRadius: 'var(--border-radius)',
                fontSize: '0.9rem',
                fontWeight: '500',
                transition: 'all 0.3s ease'
              }}
              onMouseEnter={(e) => e.target.style.transform = 'scale(1.05)'}
              onMouseLeave={(e) => e.target.style.transform = 'scale(1)'}
            >
              👨‍💼 Ứng viên
            </button>
            <button
              onClick={() => handleDemoLogin('employer')}
              disabled={loading}
              className="btn"
              style={{
                backgroundColor: 'var(--warning-color)',
                color: 'white',
                border: 'none',
                padding: '0.75rem',
                borderRadius: 'var(--border-radius)',
                fontSize: '0.9rem',
                fontWeight: '500',
                transition: 'all 0.3s ease'
              }}
              onMouseEnter={(e) => e.target.style.transform = 'scale(1.05)'}
              onMouseLeave={(e) => e.target.style.transform = 'scale(1)'}
            >
              🏢 Nhà tuyển dụng
            </button>
            <button
              onClick={() => handleDemoLogin('admin')}
              disabled={loading}
              className="btn"
              style={{
                backgroundColor: 'var(--success-color)',
                color: 'white',
                border: 'none',
                padding: '0.75rem',
                borderRadius: 'var(--border-radius)',
                fontSize: '0.9rem',
                fontWeight: '500',
                transition: 'all 0.3s ease'
              }}
              onMouseEnter={(e) => e.target.style.transform = 'scale(1.05)'}
              onMouseLeave={(e) => e.target.style.transform = 'scale(1)'}
            >
              👑 Admin
            </button>
          </div>
        </div>

        <div style={{ textAlign: 'center' }}>
          <p style={{ color: 'var(--text-secondary)', marginBottom: '1rem' }}>
            Chưa có tài khoản?
          </p>
          <button
            onClick={() => navigate('/register')}
            className="btn btn-secondary"
            style={{
              backgroundColor: 'transparent',
              border: '2px solid var(--primary-color)',
              color: 'var(--primary-color)',
              padding: '0.75rem 1.5rem',
              borderRadius: 'var(--border-radius)',
              fontWeight: '500',
              transition: 'all 0.3s ease'
            }}
            onMouseEnter={(e) => {
              e.target.style.backgroundColor = 'var(--primary-color)';
              e.target.style.color = 'white';
            }}
            onMouseLeave={(e) => {
              e.target.style.backgroundColor = 'transparent';
              e.target.style.color = 'var(--primary-color)';
            }}
          >
            📝 Đăng ký ngay
          </button>
        </div>
      </div>
    </div>
  );
}

export default Login;
